package co.istad.makara.account.application;import co.istad.makara.account.application.dto.create.CreateAccountRequest;import co.istad.makara.account.application.dto.create.CreateAccountResponse;import co.istad.makara.account.application.dto.create.CreateDepositRequest;import co.istad.makara.account.application.dto.create.CreateDepositResponse;import co.istad.makara.account.application.mapper.AccountMapper;import co.istad.makara.account.domain.command.CreateAccountCommand;import co.istad.makara.account.domain.valueobject.AccountStatus;import co.istad.makara.common.domain.valueobject.AccountId;import lombok.RequiredArgsConstructor;import lombok.extern.slf4j.Slf4j;import org.axonframework.commandhandling.gateway.CommandGateway;import org.springframework.stereotype.Service;import java.util.UUID;@Service@Slf4j@RequiredArgsConstructorpublic class AccountServiceImpl implements AccountService{    private final AccountMapper accountMapper;    private final CommandGateway commandGateway;    @Override    public CreateAccountResponse createAccount(CreateAccountRequest createAccountRequest) {        log.info("CreateAccountRequest: {}", createAccountRequest);        CreateAccountCommand createAccountCommand = accountMapper.toCreateAccountCommand(                new AccountId(UUID.randomUUID()),                createAccountRequest);        AccountId accountId = commandGateway.sendAndWait(createAccountCommand);        return CreateAccountResponse.builder()                .accountId(accountId.value().toString())                .accountHolder(createAccountRequest.accountHolder())                .accountNumber(createAccountRequest.accountNumber())                .message("Account created successfully")                .build();    }    @Override    public CreateDepositResponse depositAmount(CreateDepositRequest request) {        return null;    }}